 1	import { Button, Popover, Text, TextVariants } from '@patternfly/react-core';
 2	import * as React from 'react';
 3	import { useTranslation } from 'react-i18next';
 4	import { FilterDefinition } from '../../../model/filters';
 5	import { Link } from '../../../utils/url';
 6	import './filter-hints.css';
 7	
 8	export interface FilterHintsProps {
 9	  def: FilterDefinition;
10	}
11	
12	export const FilterHints: React.FC<FilterHintsProps> = ({ def }) => {
13	  const { t } = useTranslation('plugin__netobserv-plugin');
14	  if (!def.hint) {
15	    return null;
16	  }
17	  return (
18	    <div data-test="tips" id="tips">
19	      <Text component={TextVariants.p}>{def.hint}</Text>
20	      {def.examples && (
21	        <Popover
22	          aria-label="Hint popover"
23	          headerContent={def.name}
24	          footerContent={
25	            def.docUrl ? (
26	              <Button
27	                variant="link"
28	                component={(props: React.FunctionComponent) => (
29	                  <Link {...props} target="_blank" to={{ pathname: def.docUrl }} />
30	                )}
31	              >
32	                {t('Show related documentation')}
33	              </Button>
34	            ) : undefined
35	          }
36	          bodyContent={<div className="text-left-pre">{def.examples}</div>}
37	          hasAutoWidth={true}
38	          position={'bottom'}
39	        >
40	          <Button data-test="more" id="more" variant="link">
41	            {t('Learn more')}
42	          </Button>
43	        </Popover>
44	      )}
45	    </div>
46	  );
47	};

